#include <stdlib.h>
#include <stdio.h>
#include <string.h>
#include <math.h>
#include <sys/time.h>

#define MAX_ARGS 10
#define REC_LENGTH 49	
#define REC_WINDOW 10	
#define LATITUDE_POS 28	
#define OPEN 10000	

struct neighbor {
	char entry[REC_LENGTH];
	double dist;
};

__device__ float my_atof(const char *str) {
    float result = 0.0f;
    float sign = 1.0f;
    int i = 0;
    // Skip whitespace
    while (str[i] == ' ' || str[i] == '\t') i++;
    // Handle sign
    if (str[i] == '-') {
        sign = -1.0f;
        i++;
    } else if (str[i] == '+') {
        i++;
    }
    // Integer part
    while (str[i] >= '0' && str[i] <= '9') {
        result = result * 10.0f + (str[i] - '0');
        i++;
    }
    // Fractional part
    if (str[i] == '.') {
        i++;
        float frac = 0.0f;
        float base = 0.1f;
        while (str[i] >= '0' && str[i] <= '9') {
            frac += (str[i] - '0') * base;
            base *= 0.1f;
            i++;
        }
        result += frac;
    }
    return sign * result;
}

__global__ void compute_distances(float *z, char *sandbox, int rec_count, float target_lat, float target_long) {
    int i = blockIdx.x * blockDim.x + threadIdx.x;
    if (i < rec_count) {
        char *rec_iter = sandbox + (i * REC_LENGTH + LATITUDE_POS - 1);
        float tmp_lat = my_atof(rec_iter);
        float tmp_long = my_atof(rec_iter + 5);
        z[i] = sqrtf((tmp_lat - target_lat) * (tmp_lat - target_lat) + (tmp_long - target_long) * (tmp_long - target_long));
    }
}

int main(int argc, char* argv[]) {
    clock_t time0 = clock();
    FILE   *flist,*fp;
    int    i=0,j=0, k=0, rec_count=0, done=0;
    char   sandbox[REC_LENGTH * REC_WINDOW], dbname[64];
    struct neighbor *neighbors = NULL;
    float target_lat, target_long;

    if(5 > argc) {
        fprintf(stderr, "Invalid set of arguments\n");
        exit(-1);
    }

    flist = fopen(argv[1], "r");
    if(!flist) {
        printf("error opening flist\n");
        exit(1);
    }

    k = atoi(argv[2]);
    target_lat = atof(argv[3]);
    target_long = atof(argv[4]);

    neighbors = (struct neighbor*)malloc(k*sizeof(struct neighbor));
    if(neighbors == NULL) {
        fprintf(stderr, "no room for neighbors\n");
        exit(0);
    }

    for(j = 0; j < k; j++) { 
        neighbors[j].dist = OPEN;
    }

    if(fscanf(flist, "%s\n", dbname) != 1) {
        fprintf(stderr, "error reading filelist\n");
        exit(0);
    }

    fp = fopen(dbname, "r");
    if(!fp) {
        printf("error opening flist\n");
        exit(1);
    }

    float *z = (float *) malloc(REC_WINDOW * sizeof(float));
    float *d_z;
    char *d_sandbox;

    cudaMalloc((void**)&d_z, REC_WINDOW * sizeof(float));
    cudaMalloc((void**)&d_sandbox, REC_LENGTH * REC_WINDOW * sizeof(char));

    while(!done) {
        rec_count = fread(sandbox, REC_LENGTH, REC_WINDOW, fp);
        if(REC_WINDOW != rec_count) {
            if(!ferror(flist)) {
                fclose(fp);
                if(feof(flist))
                    done = 1;
                else {
                    if(fscanf(flist, "%s\n", dbname) != 1) {
                        fprintf(stderr, "error reading filelist\n");
                        exit(0);
                    }
                    fp = fopen(dbname, "r");
                    if(!fp) {
                        printf("error opening a db\n");
                        exit(1);
                    }
                }
            } else {
                perror("Error");
                exit(0);
            }
        }

        cudaMemcpy(d_sandbox, sandbox, REC_LENGTH * rec_count * sizeof(char), cudaMemcpyHostToDevice);

        int threadsPerBlock = 128;
        int blocksPerGrid = (rec_count + threadsPerBlock - 1) / threadsPerBlock;
        compute_distances<<<blocksPerGrid, threadsPerBlock>>>(d_z, d_sandbox, rec_count, target_lat, target_long);
        cudaDeviceSynchronize();

        cudaMemcpy(z, d_z, rec_count * sizeof(float), cudaMemcpyDeviceToHost);

        for(i = 0; i < rec_count; i++) {
            float max_dist = -1;
            int max_idx = 0;
            for(j = 0; j < k; j++) {
                if(max_dist < neighbors[j].dist) {
                    max_dist = neighbors[j].dist;
                    max_idx = j;
                }
            }
            if(neighbors[max_idx].dist > z[i]) {
                sandbox[(i+1)*REC_LENGTH-1] = '\0';
                strcpy(neighbors[max_idx].entry, sandbox + i*REC_LENGTH);
                neighbors[max_idx].dist = z[i];
            }
        }
    }

    fprintf(stderr, "The %d nearest neighbors are:\n", k);
    for(j = 0; j < k; j++) {
        if(!(OPEN == neighbors[j].dist))
            fprintf(stderr, "%s --> %f\n", neighbors[j].entry, neighbors[j].dist);
    }

    fclose(flist);

    cudaFree(d_z);
    cudaFree(d_sandbox);
    free(z);
    free(neighbors);

    clock_t time1 = clock();
    printf("total time : %15.12f s", (float)(time1 - time0) / 1000000);
    return 0;
}
